# Let's also extract the full error context from binlog with a better analyzer
cd /tmp/analyze-binlog && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-103a3bce941949f6a6c3db64d8090d77/build.binlog");

// Get all errors with full context
var errors = build.FindChildrenRecursive<Error>();
Console.WriteLine($"=== ALL BUILD ERRORS ({errors.Count}) ===\n");
int i = 1;
foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    var target = error.GetNearestParent<Target>();
    Console.WriteLine($"Error #{i}:");
    Console.WriteLine($"  Project: {project?.Name ?? "unknown"}");
    Console.WriteLine($"  Target: {target?.Name ?? "unknown"}");
    Console.WriteLine($"  Code: {error.Code}");
    Console.WriteLine($"  File: {error.File}:{error.LineNumber},{error.ColumnNumber}");
    Console.WriteLine($"  Message: {error.Text}");
    Console.WriteLine();
    i++;
}

// Check if Api failed due to cascading
Console.WriteLine("=== PROJECT BUILD RESULTS (Build target only) ===");
var buildProjects = build.FindChildrenRecursive<Project>()
    .Where(p => p.Name != null && !p.Name.Contains("metaproj"));
foreach (var proj in buildProjects.GroupBy(p => p.Name))
{
    var anyErrors = proj.Any(p => p.FindChildrenRecursive<Error>().Any());
    Console.WriteLine($"  {proj.Key}: HasErrors={anyErrors}");
}
EOF
